  1	import * as React from 'react';
  2	import { StorageClassEncryptionKMSID } from '@odf/ocs/storage-class/sc-form';
  3	import {
  4	  fieldRequirementsTranslations,
  5	  formSettings,
  6	  getName,
  7	  ReclaimPolicy,
  8	  StorageClassModel,
  9	  StorageClassResourceKind,
 10	  TextInputWithFieldRequirements,
 11	  useYupValidationResolver,
 12	  VolumeBindingMode,
 13	} from '@odf/shared';
 14	import validationRegEx from '@odf/shared/utils/validation';
 15	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 16	import { useForm } from 'react-hook-form';
 17	import { useTranslation } from 'react-i18next';
 18	import * as Yup from 'yup';
 19	import {
 20	  Checkbox,
 21	  Dropdown,
 22	  DropdownItem,
 23	  DropdownList,
 24	  FormGroup,
 25	  FormHelperText,
 26	  HelperText,
 27	  HelperTextItem,
 28	  MenuToggle,
 29	  MenuToggleElement,
 30	  TextInputTypes,
 31	} from '@patternfly/react-core';
 32	import { CaretDownIcon } from '@patternfly/react-icons';
 33	import {
 34	  AttachStorageAction,
 35	  AttachStorageActionType,
 36	  AttachStorageFormState,
 37	} from './state';
 38	
 39	type StorageClassFormProps = {
 40	  state: AttachStorageFormState;
 41	  dispatch: React.Dispatch<AttachStorageAction>;
 42	};
 43	
 44	const StorageClassForm: React.FC<StorageClassFormProps> = ({
 45	  state,
 46	  dispatch,
 47	}) => {
 48	  const { t } = useTranslation();
 49	  const [isReclaimOpen, setIsReclaimOpen] = React.useState(false);
 50	  const [isVolumeBindingOpen, setIsVolumeBindingOpen] = React.useState(false);
 51	  const onEncryptionChange = React.useCallback(() => {
 52	    dispatch({
 53	      type: AttachStorageActionType.SET_STORAGECLASS_ENCRYPTION,
 54	      payload: !state.storageClassDetails.enableStorageClassEncryption,
 55	    });
 56	  }, [dispatch, state.storageClassDetails.enableStorageClassEncryption]);
 57	  const onEncryptionKMSIDChange = (
 58	    _id: string,
 59	    paramName: string,
 60	    _checkbox: boolean
 61	  ) => {
 62	    dispatch({
 63	      type: AttachStorageActionType.SET_ENCRYPTION_KMS_ID,
 64	      payload: paramName,
 65	    });
 66	  };
 67	
 68	  const [data, loaded, loadError] = useK8sWatchResource<
 69	    StorageClassResourceKind[]
 70	  >({
 71	    kind: StorageClassModel.kind,
 72	    namespaced: false,
 73	    isList: true,
 74	  });
 75	
 76	  const { schema, fieldRequirements } = React.useMemo(() => {
 77	    const existingNames =
 78	      loaded && !loadError ? data?.map((dataItem) => getName(dataItem)) : [];
 79	
 80	    const fieldRequirements = [
 81	      fieldRequirementsTranslations.maxChars(t, 253),
 82	      fieldRequirementsTranslations.startAndEndName(t),
 83	      fieldRequirementsTranslations.alphaNumericPeriodAdnHyphen(t),
 84	      fieldRequirementsTranslations.cannotBeUsedBefore(t),
 85	    ];
 86	
 87	    const schema = Yup.object({
 88	      'attach-storage-storageclass-name': Yup.string()
 89	        .required()
 90	        .max(253, fieldRequirements[0])
 91	        .matches(
 92	          validationRegEx.startAndEndsWithAlphanumerics,
 93	          fieldRequirements[1]
 94	        )
 95	        .matches(
 96	          validationRegEx.alphaNumericsPeriodsHyphensNonConsecutive,
 97	          fieldRequirements[2]
 98	        )
 99	        .test(
100	          'unique-name',
101	          fieldRequirements[3],
102	          (value: string) => !existingNames.includes(value)
103	        ),
104	    });
105	
106	    return { schema, fieldRequirements };
107	  }, [data, loadError, loaded, t]);
108	
109	  const resolver = useYupValidationResolver(schema);
110	  const { control, trigger, setValue } = useForm({
111	    ...formSettings,
112	    resolver,
113	  });
114	
115	  const reclaimPolicyDropdownItems = React.useMemo(() => {
116	    return Object.values(ReclaimPolicy).map((policy) => (
117	      <DropdownItem
118	        key={`reclaim-policy-${policy}`}
119	        component="button"
120	        id={policy}
121	        data-test-id="reclaim-policy-dropdown-item"
122	        onClick={() =>
123	          dispatch({
124	            type: AttachStorageActionType.SET_STORAGECLASS_RECLAIM_POLICY,
125	            payload: policy,
126	          })
127	        }
128	      >
129	        {policy}
130	      </DropdownItem>
131	    ));
132	  }, [dispatch]);
133	
134	  const volumeBindingModeDropdownItems = React.useMemo(() => {
135	    return Object.values(VolumeBindingMode).map((mode) => (
136	      <DropdownItem
137	        key={`volume-binding-mode-${mode}`}
138	        component="button"
139	        id={mode}
140	        data-test-id="volume-binding-dropdown-item"
141	        onClick={() =>
142	          dispatch({
143	            type: AttachStorageActionType.SET_STORAGECLASS_VOLUME_BINDING_MODE,
144	            payload: mode,
145	          })
146	        }
147	      >
148	        {mode}
149	      </DropdownItem>
150	    ));
151	  }, [dispatch]);
152	
153	  const reclaimPolicyToggle = (toggleRef: React.Ref<MenuToggleElement>) => (
154	    <MenuToggle
155	      ref={toggleRef}
156	      id="reclaim-policy-dropdown"
157	      data-test="reclaim-policy-dropdown"
158	      onClick={() => setIsReclaimOpen(!isReclaimOpen)}
159	      isExpanded={isReclaimOpen}
160	      icon={<CaretDownIcon />}
161	      isFullWidth
162	    >
163	      {state.storageClassDetails.reclaimPolicy || t('Select reclaim policy')}
164	    </MenuToggle>
165	  );
166	
167	  const volumeBindingModeToggle = (toggleRef: React.Ref<MenuToggleElement>) => (
168	    <MenuToggle
169	      ref={toggleRef}
170	      id="volume-binding-mode-dropdown"
171	      data-test="volume-binding-mode-dropdown"
172	      onClick={() => setIsVolumeBindingOpen(!isVolumeBindingOpen)}
173	      isExpanded={isVolumeBindingOpen}
174	      icon={<CaretDownIcon />}
175	      isFullWidth
176	    >
177	      {state.storageClassDetails.volumeBindingMode ||
178	        t('Select VolumeBinding Mode')}
179	    </MenuToggle>
180	  );
181	
182	  return (
183	    <div className="odf-create-storage-class__form">
184	      <div className="form-group attachstorage-storageclass-dropdown__input">
185	        <label
186	          className="control-label co-required"
187	          htmlFor="reclaim-policy-dropdown"
188	        >
189	          {t('Reclaim Policy')}
190	        </label>
191	        <Dropdown
192	          className="dropdown--full-width"
193	          isOpen={isReclaimOpen}
194	          onSelect={() => setIsReclaimOpen(false)}
195	          onOpenChange={(open: boolean) => setIsReclaimOpen(open)}
196	          toggle={reclaimPolicyToggle}
197	          popperProps={{ width: 'trigger' }}
198	        >
199	          <DropdownList>{reclaimPolicyDropdownItems}</DropdownList>
200	        </Dropdown>
201	        <FormHelperText>
202	          <HelperText id="reclaim-policy-helper">
203	            <HelperTextItem>
204	              {t(
205	                "Determines what happens to persistent volumes when the associated persistent volume claim is deleted. Defaults to 'Delete'"
206	              )}
207	            </HelperTextItem>
208	          </HelperText>
209	        </FormHelperText>
210	      </div>
211	      <div className="form-group attachstorage-storageclass-dropdown__input">
212	        <label
213	          className="control-label co-required"
214	          htmlFor="volume-binding-mode-dropdown"
215	        >
216	          {t('Volume Binding Mode')}
217	        </label>
218	        <Dropdown
219	          className="dropdown--full-width"
220	          isOpen={isVolumeBindingOpen}
221	          onSelect={() => setIsVolumeBindingOpen(false)}
222	          onOpenChange={(open: boolean) => setIsVolumeBindingOpen(open)}
223	          toggle={volumeBindingModeToggle}
224	          popperProps={{ width: 'trigger' }}
225	        >
226	          <DropdownList>{volumeBindingModeDropdownItems}</DropdownList>
227	        </Dropdown>
228	        <FormHelperText>
229	          <HelperText id="volume-binding-helper">
230	            <HelperTextItem>
231	              {t(
232	                "Determines what persistent volume claims will be provisioned and bound. Defaults to 'WaitForFirstCustomer'"
233	              )}
234	            </HelperTextItem>
235	          </HelperText>
236	        </FormHelperText>
237	      </div>
238	      <FormGroup
239	        className="attachstorage-storageclass__text-input "
240	        fieldId="attachstorage-storageclass"
241	      >
242	        <TextInputWithFieldRequirements
243	          control={control}
244	          fieldRequirements={fieldRequirements}
245	          defaultValue={state.storageClassDetails.name}
246	          popoverProps={{
247	            headerContent: t('Name requirements'),
248	            footerContent: `${t('Example')}: my-storage-class`,
249	          }}
250	          formGroupProps={{
251	            label: t('New StorageClass name'),
252	            fieldId: 'attach-storage-storageclass-name',
253	          }}
254	          textInputProps={{
255	            id: 'attach-storage-storageclass-name',
256	            name: 'attach-storage-storageclass-name',
257	            type: TextInputTypes.text,
258	            value: state.storageClassDetails.name,
259	            placeholder: 'Enter a unique StorageClass name',
260	            'data-test': 'attach-storage-storageclass-name',
261	            isRequired: true,
262	            onChange: async (_event, val) => {
263	              // First set the value in the form state
264	              setValue('attach-storage-storageclass-name', val, {
265	                shouldValidate: true,
266	              });
267	              // Then trigger validation to get the result
268	              const isFieldValid = await trigger(
269	                'attach-storage-storageclass-name'
270	              );
271	              dispatch({
272	                type: AttachStorageActionType.SET_STORAGECLASS_NAME,
273	                payload: isFieldValid ? val : '',
274	              });
275	            },
276	          }}
277	        />
278	      </FormGroup>
279	      <FormGroup>
280	        <Checkbox
281	          id="enable-encryption-storage-class"
282	          label={t('Enable encryption on StorageClass')}
283	          className="pf-v6-u-pt-md"
284	          isChecked={state.storageClassDetails.enableStorageClassEncryption}
285	          onChange={onEncryptionChange}
286	        />
287	        {!!state.storageClassDetails.enableStorageClassEncryption && (
288	          <StorageClassEncryptionKMSID
289	            onParamChange={onEncryptionKMSIDChange}
290	            parameterKey=""
291	            parameterValue={state.storageClassDetails.encryptionKMSID}
292	          />
293	        )}
294	      </FormGroup>
295	    </div>
296	  );
297	};
298	
299	export default StorageClassForm;

